// Script Continued Below
var TaskerDurationCalculator = Class.create();
TaskerDurationCalculator.prototype = {
    initialize: function() {
		this.dc = new Tasker_Copy_DurationCalculator();
		this.hoursInBusinessDay = 9;
		// default is "8-5 weekdays excluding holidays";
		this.taskerDefaultscheduleName = gs.getProperty("x_153465_discovert.Global Template Default Schedule") + '';
		this.taskerDefaultScheduleId =  this.getDefaultScheduleId();
		// default the schedule used, but leave the default set for future calls
		this.scheduleName = this.taskerDefaultscheduleName + '';
		this.scheduleId = this.taskerDefaultScheduleId + '';
    },

	// STRY0110317
	// gr                      - GlideRecord       - used for OU schedule override
	// startTime               - GlideDateTime     - start Day and Time to check and update
	// Returns startTime       - GlideDateTime     - Date time object used to get the expected start 
	checkStartTime: function (gr, startTime){
		var msToAdd;
		this.setDurationCaluclationSchedule(gr,this.dc);
		var sch = new GlideSchedule(this.scheduleId); //use your scheudle sysid here
		if(!sch.isInSchedule(startTime)){
			msToAdd = sch.whenNext(startTime);
			startTime.addSeconds(msToAdd/1000);
		} else {
			// check if at end of day
			var gStart = new GlideDateTime(startTime);
			var endOfDay = this.calculateEndOfDay(gr, gStart.getLocalDate());
			if(endOfDay == startTime){
				// at end of day, move forward one second, then get next
				startTime.addSeconds(1);
				// now move to the start of the next day
				msToAdd = sch.whenNext(startTime);
				startTime.addSeconds(msToAdd/1000);
			}
		}
		return startTime;
	},

	//STRY0099280 
	calculateEndOfDay: function (gr,strDate){
		this.setDurationCaluclationSchedule(gr,this.dc);
		var sch = new GlideSchedule(this.scheduleId); //use your scheudle sysid here
		var gDateStart = new GlideDate();
		gDateStart.setValue(strDate);
		var gdtStart = new GlideDateTime();
		var gTimeStart = new GlideTime();
		var gDateEnd = new GlideDate();
		var gdtEndOfDay = new GlideDateTime();
		var gTimeEnd = new GlideTime();
		var gdtEnd = new GlideDateTime();
		var secondsToAdd;
		var startTime;

		// Get the start time for the day (NOTE: if there is no time in the schedule for today, this will find the next day in the schedule)
		gTimeStart.setDisplayValue("00:00:00");
		startTime = gTimeStart.getDisplayValue();
		gdtStart.setDisplayValue(gDateStart.getDisplayValue() + " " + startTime);
		if(!sch.isInSchedule(gdtStart)){
			var milliseconds = sch.whenNext(gdtStart);
			gdtStart.addSeconds(milliseconds/1000);
		}

		// now get end time for the day
		gTimeEnd.setDisplayValue("23:59:59");
		// get the date found if out of schedule above or the date passed in
		gDateEnd = gdtStart.getDate();
		gdtEndOfDay.setDisplayValue(gDateEnd.getDisplayValue() + " " + gTimeEnd.getDisplayValue());
		// get the scheduled duration for the day
		secondsToAdd = parseInt(this.dc.calcScheduleDuration(/* GlideDateTime or String */ gdtStart, /* GlideDateTime or String */ gdtEndOfDay));
		this.dc.setStartDateTime(gdtStart);
		this.dc.calcDuration(secondsToAdd);
		gdtEnd = this.dc.getEndDateTime();

		// was the 2 lines below and worked without applying to schedule that might have a gap.
		//gdtEnd = gdtStart;
		//gdtEnd.addSeconds(secondsToAdd);

		return gdtEnd;
	},

	// find the number of business days in the duration assuming 9 hour day TODO: determine how to find the number of hours per day in the schedule.
	calculateBusinessDays: function(d){
		// Divide the duration from milliseconds to hours - 60x60x1000
		var hoursCalc = d/(60*60*1000); 
		// Find # of business days by rounding down the number of days into 24 hour blocks (ignoring additional hours for now)
		var businessDays = Math.floor(hoursCalc / 24); 
		// Establish whether the rounding has removed any "whole hours" by calculating the difference between rounded business days and total duration.
		var hoursDiff = d - businessDays*60*60*24*1000;

		// Set the amount for the duration calculation based on business days in MS + the difference in hours.
		var durCalc = businessDays*(60*60*this.hoursInBusinessDay*1000)+hoursDiff;

		return durCalc;
	},

	calculateDateOfAddedBusinessDays: function(gr, days, startDate) {
		this.setDurationCaluclationSchedule(gr,this.dc);
		return this.calculateDateOfAddedBusinessDaysWitScheduleId(this.scheduleId,days,startDate);
	},

// STRY0102134
	// calculate full days and ignore the number of hours.  
	// There may be a better way, but this will take the start and the number of days to add
	// it will add one day at a time to the schedule and only count the days in the schedule
	// it will count until it reaches the number of days to add, then add that many calendar days and return the date to the caller
	calculateDateOfAddedBusinessDaysWitScheduleId: function(scheduleId, daysToAdd, startDate){
		var lEndDate = new GlideDateTime(startDate);
		var lDaysToAdd = isNaN(daysToAdd)?undefined:parseInt(daysToAdd);
		if(lDaysToAdd == undefined  || lDaysToAdd <= 0){
			return null;
		}
		var daysAdded = 0;
		var sch;
		if(scheduleId != ''){
			sch = new GlideSchedule(scheduleId); //use your scheudle sysid here
			// keep adding days and counting only the days in the schedule until you get to the number of days to add
			while(daysAdded < lDaysToAdd){
				// add one day at at time
				lEndDate.addDaysLocalTime(1);
				if(sch.isInSchedule(lEndDate)){
					// each time a day is in the schedule add one to the days added
					daysAdded++;
				} else {
					// the date/time was not in the schedule, find the next time in schedule and reset the date found
					var milliseconds = sch.whenNext(lEndDate);
					lEndDate.addSeconds(milliseconds/1000);
					daysAdded++;
				}
			}
			return lEndDate;
		} else {
			// no schedule given, just add the days
			lEndDate.addDaysLocalTime(lDaysToAdd);
		}
		return lEndDate;
	},

	// STRY0102134
	// calls the calculateEndDate function after converting a number of days to a duration
	calculateEndDateUsingDays: function (gr,  days, std){
		// convert days to a duration of business days
		var daysAsDurtion = days*60*60*24*1000;
		return this.calculateEndDate(gr, daysAsDurtion, std);
	},

	// NOTE: The initial implementation uses a system property and all templates will use that schedule to block days.
	//       In this function we will be able to set the schedule based on any values passed in the current record.
	//       If we want to set it based on the user, we could look at the sys_user table to find their default schedule.
	//       If we want to use the Primary Office, Tasking Authority or Primary Assignee, we could set a default schedule and pull here.
	//       We could also allow each Template to set a schedule.  Or, we could allow each Template Task to overide/set their own schedule.
	//       Finally, if we want to allow users to select a schedule when creating a schedule, we could grab it from there too.

	// gr:  Glide record - for initial implementation it will be Template task. (today ignored)
	//      This could be any Tasker Object and we would need to determine how to get the schedule
	//      for that object in the future.
	// d:   duration object - Duration between start and end dateTime
	// std: Start Date Time - glide date time - the start date time to add the duration to
	calculateEndDate: function(gr, d, std) {
		this.setDurationCaluclationSchedule(gr,this.dc);
		this.dc.setStartDateTime(std);
		if(this.scheduleName != ''){
			// convert days to business days
			var businessDuration = this.calculateBusinessDays(d);

			// convert duration to seconds by dividing by 1000
			this.dc.calcDuration(businessDuration/1000);
			return this.dc.getEndDateTime();
		} else {
			std.add(d);
			return std.getValue();
		}
	},

	getOUsWithScheduleOverride: function(aOUsToCheck){
		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		var aOverrideOUs = [];
		for (i=0; i<aOUsToCheck.length; i++) {
			if(grOU.get(aOUsToCheck[i])){
				if(grOU.getDisplayValue('u_schedule_override') + '' != ''){
					var oOUSchedule = {};
					oOUSchedule.ouId = aOUsToCheck[i];
					oOUSchedule.scheduleId = grOU.getValue('u_schedule_override');
					aOverrideOUs.push(oOUSchedule);
				}
			}
		}
		return aOverrideOUs;
	},

	// dc: Duration Calculator - this is the duration calculator object from ServiceNow
	getDefaultScheduleId: function(){
		var scheduleId = '';
		// Load the schedule set in the system property.  See note above for future options.
		var grSched = new GlideRecord('cmn_schedule');
		grSched.addQuery('name', this.taskerDefaultscheduleName);
		grSched.query();
		if(grSched.next()){
			scheduleId = grSched.getUniqueValue();
		} else {
			gs.warn('*** Could not find schedule "'+ this.taskerDefaultscheduleName +'"');
		}
		return scheduleId;
	},

	// gr: Glide record - for initial implementation it will be Template task. (today ignored)
	//     This could be any Tasker Object and we would need to determine how to get the schedule
	//     for that object in the future.
	// dc: Duration Calculator - this is the duration calculator object from ServiceNow
	setDurationCaluclationSchedule: function(gr, dc){
		var scheduleId = '';
		// OU should always hit here...
		if(gr && gr.u_schedule_override  && gr.getDisplayValue('u_schedule_override') + '' != ''){
			scheduleId = gr.getValue('u_schedule_override');
			this.scheduleName = gr.getDisplayValue('u_schedule_override');
		} else if(gr){
			switch (gr.getRecordClassName()){
				case 'x_153465_discovert_route_task_instance':
				case 'x_153465_discovert_route_tasks':
				case 'x_153465_discovert_discover_routing_template':
					var primary_office = '';
					// look up Primary Office and see if there is an override on the Primary Office
					// NOTE: if we decide on other / prefered overrides like top or tree is primary office and per task is Primary assignee
					if(gr.primary_office){
						primary_office = gr.getValue('primary_office');
					} else if(gr.u_primary_office){
						primary_office = gr.getValue('primary_office');
					}
					if(primary_office != ''){
						var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
						if(grOU.get(primary_office)){
							if(grOU.u_schedule_override){
								this.scheduleName = grOU.getDisplayValue('u_schedule_override');
								scheduleId = grOU.getValue('u_schedule_override');
							}
						}
					}
					break;
			}
		} 
		// if here, no overrrides were found.  Set using default
		if (scheduleId == '') {
			// Load the schedule set in the system property.  See note above for future options.
			var grSched = new GlideRecord('cmn_schedule');
			grSched.addQuery('name', this.taskerDefaultscheduleName);
			grSched.query();
			if(grSched.next()){
				scheduleId = grSched.getUniqueValue();
				this.scheduleName = this.taskerDefaultscheduleName;
			} else {
				gs.warn('*** Could not find schedule "'+ this.taskerDefaultscheduleName +'"');
			}

		}
		this.scheduleId = scheduleId;
		if(scheduleId != ''){
			dc.setSchedule(scheduleId);			
		}
	},

	// scheduleOverride: name of the schedule to lookup
	//          returns: schedule ID
	getScheduleID: function(scheduleOverride){
		// check schedule override
		var scheduleId='';
		var grSched = new GlideRecord('cmn_schedule');
		if(scheduleOverride != ''){
			grSched.addQuery('name', scheduleOverride);
			grSched.query();
			if(grSched.next()){
				scheduleId =  grSched.getUniqueValue();
			} else {
				gs.warn('*** Could not find schedule "'+ scheduleOverride +'"');
			}
		} else if(this.taskerDefaultscheduleName != ''){
			// load default schedule
			grSched.addQuery('name', this.taskerDefaultscheduleName);
			grSched.query();
			if(grSched.next()){
				scheduleId =  grSched.getUniqueValue();
			} else {
				gs.warn('*** Could not find schedule "'+ this.taskerDefaultscheduleName +'"');
			}

		}
		return scheduleId;
	},	

    type: 'TaskerDurationCalculator'
};
